CREATE OR REPLACE FUNCTION fpb_tel_loan_history_in_rec ( as_conno char , as_loan_group char , as_field char ) RETURNS bigint AS $body$
DECLARE

ldc_bal  sc_com_m_receipt_item.principal_amount% TYPE;
ldc_int  sc_com_m_receipt_item.interest_amount% TYPE;
ldc_period sc_lon_m_contract.period_payment_amount% TYPE;
ldc_temp sc_lon_m_contract.period_payment_amount% TYPE;
ls_conno_clear sc_lon_m_contract.loan_contract_no% TYPE;
li_salary_time         sc_mem_m_ucf_group_position.salary_time% TYPE;
ls_drop_prin          sc_lon_m_rule.drop_prin_status% TYPE;
li_count integer;
cur_data CURSOR FOR
SELECT sc_com_m_receipt_item.principal_amount,
      sc_com_m_receipt_item.interest_amount ,
      sc_com_m_receipt_item.description
FROM  sc_com_m_receipt,
      sc_com_m_receipt_item,
      sc_lon_m_contract,
      sc_lon_m_rule
WHERE ( sc_com_m_receipt_item.receipt_no = sc_com_m_receipt.receipt_no ) and ( sc_lon_m_contract.receipt_no = sc_com_m_receipt.receipt_no ) and ( sc_com_m_receipt_item.loan_type = sc_lon_m_rule.loan_type ) and
      ( ( sc_com_m_receipt.receipt_status = '0' ) AND ( sc_lon_m_rule.loan_group_code = as_loan_group ) AND ( sc_lon_m_contract.loan_contract_no = as_conno ) );
type tabrowi_data is table of cur_data%rowtype index by integer;ltabrowi_data  tabrowi_data;


BEGIN

open cur_data;fetch cur_data bulk collect into ltabrowi_data;close cur_data;
li_count  := ltabrowi_data.Count;
ldc_bal := 0;
ldc_int := 0;
ls_conno_clear := '';
for i in 1 .. li_count loop


  ldc_bal         := ldc_bal + coalesce(ltabrowi_data[i].principal_amount,0);
  ldc_int         := ldc_int + coalesce(ltabrowi_data[i].interest_amount,0);
  ls_conno_clear  := coalesce(ltabrowi_data[i].description,'');

  if trim(both as_field ) = 'period' then
        SELECT sc_lon_m_contract.period_payment_amount,
             sc_mem_m_ucf_group_position.salary_time,
             sc_lon_m_rule.drop_prin_status
        INTO STRICT ldc_temp ,li_salary_time , ls_drop_prin
        FROM sc_lon_m_contract,
             sc_mem_m_member_work_info,
             sc_mem_m_ucf_group_position,
             sc_lon_m_rule
       WHERE ( sc_lon_m_contract.membership_no = sc_mem_m_member_work_info.membership_no ) and ( sc_mem_m_ucf_group_position.group_position = sc_mem_m_member_work_info.group_position ) and ( sc_lon_m_rule.loan_type = sc_lon_m_contract.loan_type ) and (sc_lon_m_contract.loan_contract_no = ls_conno_clear);
        if coalesce(ldc_period::text, '') = '' then ldc_period := 0;end if;
        if coalesce(li_salary_time::text, '') = '' then li_salary_time := 1;end if;
        if coalesce(ls_drop_prin::text, '') = '' then ls_drop_prin := '0';end if;
        if ls_drop_prin = '1' then
          ldc_temp := 0;
         else
          ldc_temp := ldc_temp / li_salary_time;
         end if;
         ldc_period := ldc_period + ldc_temp;
  end if;

end loop;

case trim(both as_field )
   when 'prin' THEN
      return ldc_bal;
   when 'int' THEN
      return ldc_int;
   when 'period' THEN
       return ldc_period;
   else
      return ldc_bal;
end case;


END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
